/* Months / weekday labels in Spanish */
const MESES_LBL = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
const HORAS_LBL = Array.from({length:24}, (_,i) => String(i).padStart(2,'0') + 'h');
const DIAS_LBL  = ['Lunes','Martes','Miércoles','Jueves','Viernes','Sábado','Domingo'];

/* ─────────────────────────────────────────────────────────────────
   [2] LIVE CLOCK + STATUS BAR
   ───────────────────────────────────────────────────────────────── */
function tickClock() {
  const el = document.getElementById('liveClock');
  if (!el) return;
  const d = new Date();
  el.textContent = d.toLocaleTimeString('es-CO', { hour12: false });
}
setInterval(tickClock, 1000);
tickClock();

/* ─────────────────────────────────────────────────────────────────
   [3] COUNTERS (KPI cards) — animated, real values from Excel
   ───────────────────────────────────────────────────────────────── */
function animateCounter(id, target, duration = 1400) {
  const el = document.getElementById(id);
  if (!el) return;
  const t0 = performance.now();
  const fmt = new Intl.NumberFormat('es-CO');
  const step = (now) => {
    const p = Math.min((now - t0) / duration, 1);
    const eased = 1 - Math.pow(1 - p, 3);
    el.textContent = fmt.format(Math.round(eased * target));
    if (p < 1) requestAnimationFrame(step);
  };
  requestAnimationFrame(step);
}

/* Composite risk index (geo-temporal) — derived from data, not invented */
function computeRiskIndex() {
  // share of bike events vs total + peak-hour intensity factor
  const bikeShare = DATA.totals.bici / DATA.totals.total;
  const peakHours = DATA.hora_total[6] + DATA.hora_total[7] + DATA.hora_total[17] + DATA.hora_total[18];
  const peakShare = peakHours / DATA.totals.total;
  // fatality rate factor
  const fatality = DATA.totals.muertos / DATA.totals.total;
  // weighted composite, normalised to 0-100
  const idx = Math.round(
    (bikeShare * 100) * 1.5 +     // micromobility exposure
    (peakShare * 100) * 0.9 +     // temporal concentration
    (fatality * 100) * 6.0        // severity
  );
  return Math.min(100, idx);
}

window.addEventListener('DOMContentLoaded', () => {
  setTimeout(() => {
    animateCounter('k1', DATA.totals.total);            // 13,949
    animateCounter('k2', DATA.totals.muertos);          // 551
    animateCounter('k3', DATA.totals.heridos);          // 12,361
    animateCounter('k4', DATA.totals.bici);             // 2,042
    animateCounter('k5', DATA.totals.muertos_bici);     // 79
    animateCounter('k6', computeRiskIndex());           // composite
  }, 250);

  // gauge sync
  const riskIdx = computeRiskIndex();
  const gaugeValEl = document.getElementById('gaugeVal');
  if (gaugeValEl) gaugeValEl.textContent = riskIdx;
  const arc = document.getElementById('gaugeArc');
  if (arc) {
    const C = 2 * Math.PI * 50; // circumference
    arc.setAttribute('stroke-dasharray', C.toFixed(1));
    arc.setAttribute('stroke-dashoffset', (C * (1 - riskIdx / 100)).toFixed(1));
  }
});

/* ─────────────────────────────────────────────────────────────────
   [4] CHART.JS DEFAULTS
   ───────────────────────────────────────────────────────────────── */
function configureChartDefaults() {
  if (typeof Chart === 'undefined') return false;
  Chart.defaults.color = '#94a3b8';
  Chart.defaults.font.family = "'Outfit', sans-serif";
  Chart.defaults.font.size = 11;
  Chart.defaults.borderColor = 'rgba(0,212,255,0.08)';
  return true;
}
const GR = { color: 'rgba(0,212,255,0.05)', drawBorder: false };

/* ─────────────────────────────────────────────────────────────────
   [5] BUILD CHARTS  (real Excel-derived data is injected here)
   ───────────────────────────────────────────────────────────────── */
function buildCharts() {
  if (!configureChartDefaults()) return;

  /* ─── (5.1) Hour chart — DATA.hora_total + DATA.hora_bici from Excel ─── */
  const ctxHora = document.getElementById('cHora');
  if (ctxHora) new Chart(ctxHora, {
    type: 'line',
    data: {
      labels: HORAS_LBL,
      datasets: [
        {
          label: 'Siniestros (total)',
          data: DATA.hora_total,
          borderColor: '#00d4ff',
          backgroundColor: (ctx) => {
            const c = ctx.chart.ctx.createLinearGradient(0, 0, 0, 200);
            c.addColorStop(0, 'rgba(0,212,255,0.32)');
            c.addColorStop(1, 'rgba(0,212,255,0.00)');
            return c;
          },
          fill: true, tension: 0.35,
          borderWidth: 2, pointRadius: 0, pointHoverRadius: 5
        },
        {
          label: 'Con bicicleta',
          data: DATA.hora_bici,
          borderColor: '#34d399',
          backgroundColor: 'rgba(52,211,153,0)',
          fill: false, tension: 0.35,
          borderWidth: 2, borderDash: [5,4],
          pointRadius: 0, pointHoverRadius: 5
        }
      ]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { position: 'top', labels: { boxWidth: 10, font: { size: 11 } } },
        tooltip: { backgroundColor: 'rgba(13,18,32,0.95)', borderColor: '#00d4ff', borderWidth: 1 }
      },
      scales: {
        x: { grid: GR, ticks: { maxRotation: 0, autoSkip: true, autoSkipPadding: 8 } },
        y: { grid: GR, beginAtZero: true }
      }
    }
  });

  /* ─── (5.2) Monthly chart — DATA.mes_total / mes_bici / mes_muertos ─── */
  const ctxMes = document.getElementById('cMes');
  if (ctxMes) new Chart(ctxMes, {
    type: 'bar',
    data: {
      labels: MESES_LBL,
      datasets: [
        {
          label: 'Total siniestros',
          data: DATA.mes_total,
          backgroundColor: 'rgba(0,212,255,0.14)',
          borderColor: '#00d4ff',
          borderWidth: 1.5, borderRadius: 3, order: 2
        },
        {
          label: 'Con bicicleta',
          data: DATA.mes_bici,
          backgroundColor: 'rgba(52,211,153,0.22)',
          borderColor: '#34d399',
          borderWidth: 1.5, borderRadius: 3, order: 3
        },
        {
          label: 'Fallecidos',
          data: DATA.mes_muertos,
          type: 'line',
          borderColor: '#ff4d6d',
          backgroundColor: '#ff4d6d',
          borderWidth: 2,
          pointBackgroundColor: '#ff4d6d',
          pointRadius: 4, tension: 0.4,
          yAxisID: 'y2', order: 1
        }
      ]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { position: 'top', labels: { boxWidth: 11, font: { size: 10 } } },
        tooltip: { backgroundColor: 'rgba(13,18,32,0.95)', borderColor: '#00d4ff', borderWidth: 1 }
      },
      scales: {
        x: { grid: GR },
        y: { grid: GR, title: { display: true, text: 'Siniestros', font: { size: 10 } } },
        y2: {
          position: 'right',
          grid: { display: false },
          title: { display: true, text: 'Fallecidos', font: { size: 10 } },
          ticks: { color: '#ff4d6d' }
        }
      }
    }
  });

  /* ─── (5.3) Localidades chart — DATA.localidades / localidades_bici ─── */
  const ctxLoc = document.getElementById('cLocalidad');
  if (ctxLoc) {
    const locNames = DATA.localidades.slice(0, 12).map(d => d[0]);
    const locTotals = DATA.localidades.slice(0, 12).map(d => d[1]);
    // align bici array to same locality order
    const biciMap = Object.fromEntries(DATA.localidades_bici);
    const locBici  = locNames.map(n => biciMap[n] || 0);

    new Chart(ctxLoc, {
      type: 'bar',
      data: {
        labels: locNames,
        datasets: [
          { label: 'Total siniestros', data: locTotals,
            backgroundColor: 'rgba(0,212,255,0.14)', borderColor: '#00d4ff',
            borderWidth: 1.5, borderRadius: 2 },
          { label: 'Con bicicleta', data: locBici,
            backgroundColor: 'rgba(52,211,153,0.30)', borderColor: '#34d399',
            borderWidth: 1.5, borderRadius: 2 }
        ]
      },
      options: {
        indexAxis: 'y',
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { position: 'top', labels: { boxWidth: 10, font: { size: 10 } } },
          tooltip: { backgroundColor: 'rgba(13,18,32,0.95)', borderColor: '#00d4ff', borderWidth: 1 }
        },
        scales: {
          x: { grid: GR, beginAtZero: true },
          y: { grid: { display: false }, ticks: { font: { size: 11 } } }
        }
      }
    });
  }

  /* ─── (5.4) Clase de siniestro — DATA.clase ─── */
  const ctxClase = document.getElementById('cClase');
  if (ctxClase) {
    const claseColors = ['#00d4ff', '#ff4d6d', '#fbbf24', '#a78bfa', '#64748b', '#94a3b8'];
    new Chart(ctxClase, {
      type: 'doughnut',
      data: {
        labels: DATA.clase.map(d => d[0]),
        datasets: [{
          data: DATA.clase.map(d => d[1]),
          backgroundColor: claseColors,
          borderColor: '#070a12',
          borderWidth: 3
        }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        cutout: '60%',
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: 'rgba(13,18,32,0.95)',
            borderColor: '#00d4ff', borderWidth: 1,
            callbacks: {
              label: (ctx) => {
                const pct = ((ctx.raw / DATA.totals.total) * 100).toFixed(1);
                return ` ${ctx.label}: ${ctx.raw.toLocaleString('es-CO')} (${pct}%)`;
              }
            }
          }
        }
      }
    });
  }

  /* ─── (5.5) Factores asociados — DATA.factores ─── */
  const ctxFact = document.getElementById('cFactores');
  if (ctxFact) {
    const labels = DATA.factores.map(d => d[0].replace('Con_', 'Con '));
    const colors = ['#ff4d6d','#fbbf24','#34d399','#60a5fa','#a78bfa','#f87171','#fb923c','#94a3b8'];
    new Chart(ctxFact, {
      type: 'bar',
      data: {
        labels,
        datasets: [{
          data: DATA.factores.map(d => d[1]),
          backgroundColor: colors,
          borderColor: colors,
          borderWidth: 1, borderRadius: 3
        }]
      },
      options: {
        indexAxis: 'y',
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: { backgroundColor: 'rgba(13,18,32,0.95)', borderColor: '#00d4ff', borderWidth: 1 }
        },
        scales: {
          x: { grid: GR, beginAtZero: true },
          y: { grid: { display: false }, ticks: { font: { size: 11 } } }
        }
      }
    });
  }

  /* ─── (5.6) Focus bicicleta · monthly bici vs total ─── */
  const ctxBici = document.getElementById('cBici');
  if (ctxBici) new Chart(ctxBici, {
    type: 'line',
    data: {
      labels: MESES_LBL,
      datasets: [
        {
          label: 'Siniestros con bicicleta',
          data: DATA.mes_bici,
          borderColor: '#34d399',
          backgroundColor: (ctx) => {
            const c = ctx.chart.ctx.createLinearGradient(0,0,0,160);
            c.addColorStop(0,'rgba(52,211,153,.35)');
            c.addColorStop(1,'rgba(52,211,153,0)');
            return c;
          },
          fill: true, tension: 0.4,
          borderWidth: 2,
          pointBackgroundColor: '#34d399',
          pointRadius: 4
        }
      ]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        tooltip: { backgroundColor: 'rgba(13,18,32,0.95)', borderColor: '#34d399', borderWidth: 1 }
      },
      scales: {
        x: { grid: GR },
        y: { grid: GR, beginAtZero: true }
      }
    }
  });

  /* ─── (5.7) KPI sparklines · derived series ─── */
  const sparklines = [
    { id: 'spk1', data: DATA.mes_total, color: '#00d4ff' },
    { id: 'spk2', data: DATA.mes_muertos, color: '#ff4d6d' },
    { id: 'spk3', data: DATA.mes_total.map(v => Math.round(v * 0.886)), color: '#fbbf24' }, // heridos ~88.6%
    { id: 'spk4', data: DATA.mes_bici, color: '#34d399' },
    { id: 'spk5', data: DATA.mes_bici.map(v => Math.max(1, Math.round(v * 79 / DATA.totals.bici))), color: '#a78bfa' },
    { id: 'spk6', data: DATA.hora_total, color: '#00d4ff' }
  ];
  sparklines.forEach(s => {
    const c = document.getElementById(s.id);
    if (!c) return;
    new Chart(c, {
      type: 'line',
      data: {
        labels: s.data.map((_,i) => i),
        datasets: [{
          data: s.data,
          borderColor: s.color,
          backgroundColor: (ctx) => {
            const g = ctx.chart.ctx.createLinearGradient(0,0,0,34);
            g.addColorStop(0, s.color + '40');
            g.addColorStop(1, s.color + '00');
            return g;
          },
          fill: true, tension: 0.4,
          borderWidth: 1.5, pointRadius: 0
        }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: { legend: { display: false }, tooltip: { enabled: false } },
        scales: { x: { display: false }, y: { display: false } },
        animation: { duration: 1400 }
      }
    });
  });
}

/* ─────────────────────────────────────────────────────────────────
   [6] HOUR STRIP — micro heatmap above the line chart
   ───────────────────────────────────────────────────────────────── */
function buildHourStrip() {
  const wrap = document.getElementById('hourStrip');
  if (!wrap) return;
  const max = Math.max(...DATA.hora_total);
  DATA.hora_total.forEach((v, i) => {
    const ratio = v / max;
    // gradient: cyan → yellow → red
    const r = Math.round(ratio * 239 + (1 - ratio) * 0);
    const g = Math.round((1 - Math.abs(ratio - .5) * 2) * 191 + Math.abs(ratio - .5) * 80);
    const b = Math.round((1 - ratio) * 255);
    const cell = document.createElement('div');
    cell.className = 'hcell';
    cell.dataset.h = i + 'h';
    cell.style.background = `rgba(${r},${g},${b},${0.18 + ratio * 0.72})`;
    cell.title = `${i.toString().padStart(2,'0')}h · ${v.toLocaleString('es-CO')} siniestros (${DATA.hora_bici[i]} con bici)`;
    wrap.appendChild(cell);
  });
}

/* ─────────────────────────────────────────────────────────────────
   [7] WEEK GRID
   ───────────────────────────────────────────────────────────────── */
function buildWeekGrid() {
  const wrap = document.getElementById('weekgrid');
  if (!wrap) return;
  // DATA.dia_semana arrives unordered; reorder Lun → Dom
  const order = ['lunes','martes','miércoles','jueves','viernes','sábado','domingo'];
  const map = Object.fromEntries(DATA.dia_semana);
  const max = Math.max(...order.map(d => map[d] || 0));
  order.forEach((d, i) => {
    const v = map[d] || 0;
    const ratio = v / max;
    const div = document.createElement('div');
    div.className = 'wd';
    div.innerHTML = `
      <div class="wd-name">${DIAS_LBL[i]}</div>
      <div class="wd-val">${v.toLocaleString('es-CO')}</div>
      <div class="wd-bar"><i style="width:${(ratio * 100).toFixed(0)}%"></i></div>
    `;
    wrap.appendChild(div);
  });
}

/* ─────────────────────────────────────────────────────────────────
   [8] ACTOR BARS  — derived from factores (Moto/Peat/Bici/...)
   ───────────────────────────────────────────────────────────────── */
function buildActorBars() {
  const wrap = document.getElementById('actorBars');
  if (!wrap) return;
  const actors = [
    { name: 'Moto',        key: 'Con_Moto',       color: '#ff4d6d' },
    { name: 'Peatón',      key: 'Con_Peaton',     color: '#fbbf24' },
    { name: 'Bicicleta',   key: 'Con_Bicicleta',  color: '#34d399' },
    { name: 'SITP',        key: 'Con_Sitp',       color: '#60a5fa' },
    { name: 'Taxi',        key: 'Con_Taxi',       color: '#a78bfa' },
    { name: 'Embriaguez',  key: 'Con_Embriaguez', color: '#f87171' },
    { name: 'Huecos',      key: 'Con_Huecos',     color: '#fb923c' },
    { name: 'Velocidad',   key: 'Con_Velocidad',  color: '#facc15' }
  ];
  const map = Object.fromEntries(DATA.factores);
  const max = Math.max(...actors.map(a => map[a.key] || 0));
  actors.forEach(a => {
    const v = map[a.key] || 0;
    const pct = (v / max) * 100;
    const fmt = new Intl.NumberFormat('es-CO');
    const row = document.createElement('div');
    row.className = 'abar';
    row.innerHTML = `
      <div class="abar-name">${a.name}</div>
      <div class="abar-track">
        <div class="abar-fill" style="width:${pct.toFixed(1)}%;color:${a.color};background-color:${a.color}25;"></div>
      </div>
      <div class="abar-val" style="color:${a.color}">${fmt.format(v)}</div>
    `;
    wrap.appendChild(row);
  });
}

/* ─────────────────────────────────────────────────────────────────
   [9] LEAFLET MAP — heatmap + 2,042 real bike GPS points
   ───────────────────────────────────────────────────────────────── */
let LMAP = null;
let HEATLAYER = null;
let POINTLAYER = null;
let CORRIDORLAYER = null;
let currentLayerMode = 'heat';
let currentSevFilter = new Set([3, 2]); // default visible severities
let currentHour = null; // null = all hours

function buildMap() {
  if (typeof L === 'undefined') { setTimeout(buildMap, 200); return; }
  const el = document.getElementById('leaflet');
  if (!el) return;

  LMAP = L.map(el, {
    center: [4.6500, -74.1050],
    zoom: 11,
    zoomControl: true,
    scrollWheelZoom: true,
    attributionControl: true
  });

  // dark base — CartoDB DarkMatter
  L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
    attribution: '© OpenStreetMap · © CARTO · SDM 2024',
    maxZoom: 19, subdomains: 'abcd'
  }).addTo(LMAP);

  applyMapLayer();

  // critical corridors highlighted (approximate polylines)
  CORRIDORLAYER = L.layerGroup();
  const corridors = [
    { name: 'Av. Caracas', color: '#ff4d6d',
      path: [[4.5800,-74.1000],[4.6100,-74.0900],[4.6450,-74.0790],[4.6800,-74.0680],[4.7100,-74.0580]] },
    { name: 'NQS',         color: '#fbbf24',
      path: [[4.5500,-74.1200],[4.5900,-74.1090],[4.6300,-74.0980],[4.6700,-74.0870],[4.7100,-74.0750]] },
    { name: 'Calle 80',    color: '#a78bfa',
      path: [[4.7050,-74.1450],[4.7080,-74.1100],[4.7100,-74.0750],[4.7110,-74.0500]] }
  ];
  corridors.forEach(c => {
    L.polyline(c.path, { color: c.color, weight: 4, opacity: 0.75 })
      .bindTooltip(c.name, { permanent: false, direction: 'top' })
      .addTo(CORRIDORLAYER);
  });
}

function applyMapLayer() {
  if (!LMAP) return;
  if (HEATLAYER) LMAP.removeLayer(HEATLAYER);
  if (POINTLAYER) LMAP.removeLayer(POINTLAYER);
  if (CORRIDORLAYER) LMAP.removeLayer(CORRIDORLAYER);

  // filter points by severity + hour
  const pts = DATA.bike_points.filter(p => {
    if (!currentSevFilter.has(p[2])) return false;
    if (currentHour !== null && p[3] !== currentHour) return false;
    return true;
  });

  document.getElementById('visiblePoints').textContent =
    new Intl.NumberFormat('es-CO').format(pts.length);

  if (currentLayerMode === 'heat') {
    const heatData = pts.map(p => [p[0], p[1], p[2] / 3]);
    HEATLAYER = L.heatLayer(heatData, {
      radius: 22, blur: 24, maxZoom: 16, minOpacity: 0.35,
      gradient: {
        0.20: '#00d4ff', 0.45: '#34d399',
        0.65: '#fbbf24', 0.85: '#ff4d6d', 1.0: '#ffffff'
      }
    }).addTo(LMAP);
  } else if (currentLayerMode === 'points') {
    POINTLAYER = L.layerGroup();
    pts.forEach(p => {
      const sev = p[2];
      const color = sev === 3 ? '#ff4d6d' : sev === 2 ? '#fbbf24' : '#00d4ff';
      const radius = sev === 3 ? 6 : sev === 2 ? 4 : 3;
      L.circleMarker([p[0], p[1]], {
        radius, color, fillColor: color, fillOpacity: 0.7, weight: 1
      })
      .bindPopup(`
        <div class="bike-popup">
          <b>${p[4] || 'Bogotá'}</b><br>
          ${p[3].toString().padStart(2,'0')}h · gravedad ${sev}<br>
          <span style="font-family:'Space Mono',monospace;font-size:10px;color:#94a3b8">
            ${p[0].toFixed(4)}, ${p[1].toFixed(4)}
          </span>
        </div>
      `)
      .addTo(POINTLAYER);
    });
    POINTLAYER.addTo(LMAP);
  } else if (currentLayerMode === 'corridor') {
    CORRIDORLAYER.addTo(LMAP);
    // also a faint heat under it
    const heatData = pts.map(p => [p[0], p[1], p[2] / 3]);
    HEATLAYER = L.heatLayer(heatData, {
      radius: 16, blur: 20, maxZoom: 16, minOpacity: 0.18,
      gradient: { 0.4: '#00d4ff', 0.8: '#ff4d6d', 1.0: '#ffffff' }
    }).addTo(LMAP);
  }
}

/* ─────────────────────────────────────────────────────────────────
   [10] INTERACTIVITY — sidebar filters, map toolbar
   ───────────────────────────────────────────────────────────────── */
function bindUI() {

  // map toolbar
  document.querySelectorAll('.tool-btn').forEach(b => {
    b.addEventListener('click', () => {
      document.querySelectorAll('.tool-btn').forEach(x => x.classList.remove('active'));
      b.classList.add('active');
      currentLayerMode = b.dataset.layer;
      applyMapLayer();
    });
  });

  // mode segmented
  document.querySelectorAll('#modeSeg .seg-btn').forEach(b => {
    b.addEventListener('click', () => {
      document.querySelectorAll('#modeSeg .seg-btn').forEach(x => x.classList.remove('active'));
      b.classList.add('active');
      const mode = b.dataset.mode;
      const hint = document.getElementById('modeHint');
      if (mode === 'all')      hint.textContent = `Vista agregada: ${DATA.totals.total.toLocaleString('es-CO')} siniestros 2024`;
      else if (mode === 'bici') hint.textContent = `Bicicleta: ${DATA.totals.bici.toLocaleString('es-CO')} siniestros · ${DATA.totals.muertos_bici} fallecidos`;
      else                     hint.textContent = 'Patineta eléctrica: subconjunto de "Otro" en caída de ocupante';
    });
  });

  // severity checkboxes affect heatmap
  document.querySelectorAll('[data-sev]').forEach(cb => {
    cb.addEventListener('change', () => {
      const sev = parseInt(cb.dataset.sev, 10);
      if (cb.checked) currentSevFilter.add(sev);
      else currentSevFilter.delete(sev);
      applyMapLayer();
    });
  });

  // hour range
  const rg = document.getElementById('hourRange');
  if (rg) {
    const updateRange = () => {
      const v = parseInt(rg.value, 10);
      currentHour = v;
      document.getElementById('hourPick').textContent =
        v.toString().padStart(2,'0') + 'h';
      const cnt = DATA.hora_bici[v];
      document.getElementById('hourHint').textContent =
        `${cnt} siniestros con bici a las ${v}h · gemelo geotemporal`;
      const pct = (v / 23) * 100;
      rg.style.setProperty('--p', pct + '%');
      applyMapLayer();
    };
    rg.addEventListener('input', updateRange);
    // initial sync
    rg.style.setProperty('--p', ((7/23)*100) + '%');
  }

  // smooth-scroll nav
  document.querySelectorAll('.side-nav a').forEach(a => {
    a.addEventListener('click', (e) => {
      const id = a.getAttribute('href').slice(1);
      const target = document.getElementById(id);
      if (target) {
        e.preventDefault();
        document.querySelectorAll('.side-nav a').forEach(x => x.classList.remove('active'));
        a.classList.add('active');
        target.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    });
  });
}

/* ─────────────────────────────────────────────────────────────────
   [11] BOOT
   ───────────────────────────────────────────────────────────────── */
function boot() {
  // Chart.js may load slightly later than DOMContentLoaded since it's deferred — retry
  if (typeof Chart === 'undefined') { setTimeout(boot, 100); return; }
  buildCharts();
  buildHourStrip();
  buildWeekGrid();
  buildActorBars();
  buildMap();
  bindUI();
}
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', boot);
} else {
  boot();
}
